const fs=require('fs');
const out=(o)=>[{json:o}];
const inp=$('Input').first().json||{};
function fromStr(s){s=String(s).trim();if(s.startsWith('{')){try{return JSON.parse(s);}catch(e){}}return {what:s};}
let raw=(inp.query!==undefined)?inp.query:inp; let a={};
if(typeof raw==='string'){a=fromStr(raw);}
else if(raw&&typeof raw==='object'){ if(raw.what!==undefined||raw.resource!==undefined){a=raw;} else {const f=Object.values(raw)[0]; a=(typeof f==='string')?fromStr(f):(f&&typeof f==='object'?f:raw);} }
let what=String(a.what||a.resource||'both').toLowerCase().trim();
if(!['bans','validations','both'].includes(what)) what='both';
function readLines(p){ try{return String(fs.readFileSync(p,'utf8')).split('\n').filter(Boolean).map(l=>{try{return JSON.parse(l)}catch(e){return null}}).filter(Boolean);}catch(e){return [];} }
const res={};
if(what==='bans'||what==='both'){
  const ev=readLines('/home/node/.n8n/soar_bans.jsonl'); const map={};
  for(const e of ev){
    if(e.type==='ban'){ map[e.ip+'@'+(e.agent||'')]={ip:e.ip,agent:e.agent,command:e.command,since:e.ts,duration_s:e.duration||0,active:true}; }
    else if(e.type==='unban'){ for(const k in map){ if(map[k].ip===e.ip) map[k].active=false; } }
  }
  res.banned_ips=Object.values(map).filter(x=>x.active);
  res.banned_count=res.banned_ips.length;
}
if(what==='validations'||what==='both'){
  const ev=readLines('/home/node/.n8n/soar_validations.jsonl'); const byk={}; const order=[];
  for(const e of ev){ const k=e.exec||('x'+(e.ip||'')+'|'+(e.ts||''));
    if(e.type==='request'){ byk[k]={ip:e.ip,agent:e.agent,level:e.level,rule:e.rule,requested_at:e.ts,status:'pending'}; order.push(k); }
    else if(e.type==='decision'){
      if(byk[k]){ byk[k].status=e.result; byk[k].decided_at=e.ts; }
      else { const c=Object.values(byk).filter(v=>v.ip===e.ip&&v.status==='pending'); if(c.length){ c[c.length-1].status=e.result; c[c.length-1].decided_at=e.ts; } }
    }
  }
  let list=Object.values(byk).sort((x,y)=>String(y.requested_at||'').localeCompare(String(x.requested_at||''))).slice(0,25);
  res.validations=list; res.validations_count=list.length;
}
return out(res);
